ALTER TABLE public.conversations ADD COLUMN IF NOT EXISTS direct_key text, ADD COLUMN IF NOT EXISTS updated_at timestamptz NOT NULL DEFAULT now();
CREATE UNIQUE INDEX IF NOT EXISTS conversations_direct_key_uidx ON public.conversations(direct_key) WHERE direct_key IS NOT NULL;
CREATE INDEX IF NOT EXISTS conversations_created_by_idx ON public.conversations(created_by);
ALTER TABLE public.messages DROP CONSTRAINT IF EXISTS messages_content_check;
ALTER TABLE public.messages ADD CONSTRAINT messages_content_check CHECK (deleted_at IS NOT NULL OR (kind='text' AND body IS NOT NULL AND btrim(body)<>'' AND char_length(body)<=8000) OR (kind IN ('image','file') AND attachment_path IS NOT NULL AND char_length(attachment_path)<=512));
ALTER TABLE public.messages DROP CONSTRAINT IF EXISTS messages_attachment_size_check;
ALTER TABLE public.messages ADD CONSTRAINT messages_attachment_size_check CHECK (attachment_size IS NULL OR (attachment_size>0 AND attachment_size<=31457280));
ALTER TABLE public.message_reactions DROP CONSTRAINT IF EXISTS message_reactions_emoji_check;
ALTER TABLE public.message_reactions ADD CONSTRAINT message_reactions_emoji_check CHECK (char_length(emoji) BETWEEN 1 AND 16);
CREATE INDEX IF NOT EXISTS messages_reply_to_idx ON public.messages(reply_to_id) WHERE reply_to_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS messages_sender_idx ON public.messages(sender_id);
CREATE INDEX IF NOT EXISTS message_reactions_user_idx ON public.message_reactions(user_id);
REVOKE ALL ON public.conversations,public.conversation_participants,public.messages,public.message_reactions FROM authenticated;
GRANT SELECT ON public.conversations,public.conversation_participants TO authenticated;
GRANT SELECT,INSERT ON public.messages TO authenticated;
GRANT UPDATE(body,edited_at,deleted_at,attachment_path,attachment_name,attachment_mime,attachment_size) ON public.messages TO authenticated;
GRANT SELECT,INSERT,DELETE ON public.message_reactions TO authenticated;
GRANT UPDATE(emoji) ON public.message_reactions TO authenticated;
GRANT ALL ON public.conversations,public.conversation_participants,public.messages,public.message_reactions TO service_role;
CREATE OR REPLACE FUNCTION public.is_conversation_member(_conv uuid,_user uuid) RETURNS boolean LANGUAGE sql STABLE SECURITY DEFINER SET search_path=public AS $$ SELECT EXISTS(SELECT 1 FROM public.conversation_participants WHERE conversation_id=_conv AND user_id=_user) $$;
REVOKE EXECUTE ON FUNCTION public.is_conversation_member(uuid,uuid) FROM PUBLIC,anon; GRANT EXECUTE ON FUNCTION public.is_conversation_member(uuid,uuid) TO authenticated,service_role;
CREATE OR REPLACE FUNCTION public.member_conversation_ids() RETURNS SETOF uuid LANGUAGE sql STABLE SECURITY DEFINER SET search_path=public AS $$ SELECT conversation_id FROM public.conversation_participants WHERE user_id=auth.uid() $$;
REVOKE EXECUTE ON FUNCTION public.member_conversation_ids() FROM PUBLIC,anon; GRANT EXECUTE ON FUNCTION public.member_conversation_ids() TO authenticated,service_role;
DROP POLICY IF EXISTS conv_select_member ON public.conversations; DROP POLICY IF EXISTS conv_insert_self ON public.conversations; DROP POLICY IF EXISTS conv_update_member ON public.conversations; DROP POLICY IF EXISTS conversations_member_select ON public.conversations;
CREATE POLICY conversations_member_select ON public.conversations FOR SELECT TO authenticated USING(tenant_id=(SELECT public.current_tenant_id()) AND id IN(SELECT public.member_conversation_ids()));
DROP POLICY IF EXISTS cp_select_member ON public.conversation_participants; DROP POLICY IF EXISTS cp_update_self ON public.conversation_participants; DROP POLICY IF EXISTS conversation_participants_member_select ON public.conversation_participants;
CREATE POLICY conversation_participants_member_select ON public.conversation_participants FOR SELECT TO authenticated USING(tenant_id=(SELECT public.current_tenant_id()) AND conversation_id IN(SELECT public.member_conversation_ids()));
DROP POLICY IF EXISTS msg_select_member ON public.messages; DROP POLICY IF EXISTS msg_insert_sender ON public.messages; DROP POLICY IF EXISTS msg_update_own ON public.messages; DROP POLICY IF EXISTS messages_member_select ON public.messages; DROP POLICY IF EXISTS messages_member_insert ON public.messages; DROP POLICY IF EXISTS messages_sender_update ON public.messages;
CREATE POLICY messages_member_select ON public.messages FOR SELECT TO authenticated USING(tenant_id=(SELECT public.current_tenant_id()) AND conversation_id IN(SELECT public.member_conversation_ids()));
CREATE POLICY messages_member_insert ON public.messages FOR INSERT TO authenticated WITH CHECK(sender_id=(SELECT auth.uid()) AND tenant_id=(SELECT public.current_tenant_id()) AND conversation_id IN(SELECT public.member_conversation_ids()));
CREATE POLICY messages_sender_update ON public.messages FOR UPDATE TO authenticated USING(sender_id=(SELECT auth.uid()) AND tenant_id=(SELECT public.current_tenant_id())) WITH CHECK(sender_id=(SELECT auth.uid()) AND tenant_id=(SELECT public.current_tenant_id()));
DROP POLICY IF EXISTS mr_select_member ON public.message_reactions; DROP POLICY IF EXISTS mr_write_own ON public.message_reactions; DROP POLICY IF EXISTS message_reactions_member_select ON public.message_reactions; DROP POLICY IF EXISTS message_reactions_own_insert ON public.message_reactions; DROP POLICY IF EXISTS message_reactions_own_update ON public.message_reactions; DROP POLICY IF EXISTS message_reactions_own_delete ON public.message_reactions;
CREATE POLICY message_reactions_member_select ON public.message_reactions FOR SELECT TO authenticated USING(tenant_id=(SELECT public.current_tenant_id()) AND conversation_id IN(SELECT public.member_conversation_ids()));
CREATE POLICY message_reactions_own_insert ON public.message_reactions FOR INSERT TO authenticated WITH CHECK(user_id=(SELECT auth.uid()) AND tenant_id=(SELECT public.current_tenant_id()) AND conversation_id IN(SELECT public.member_conversation_ids()));
CREATE POLICY message_reactions_own_update ON public.message_reactions FOR UPDATE TO authenticated USING(user_id=(SELECT auth.uid()) AND tenant_id=(SELECT public.current_tenant_id())) WITH CHECK(user_id=(SELECT auth.uid()) AND tenant_id=(SELECT public.current_tenant_id()));
CREATE POLICY message_reactions_own_delete ON public.message_reactions FOR DELETE TO authenticated USING(user_id=(SELECT auth.uid()) AND tenant_id=(SELECT public.current_tenant_id()));
CREATE OR REPLACE FUNCTION public.messages_before_insert() RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$ DECLARE v_tenant uuid; v_reply uuid; BEGIN SELECT tenant_id INTO v_tenant FROM public.conversations WHERE id=NEW.conversation_id; IF v_tenant IS NULL THEN RAISE EXCEPTION 'chat: conversation missing'; END IF; NEW.tenant_id:=v_tenant; IF NEW.reply_to_id IS NOT NULL THEN SELECT conversation_id INTO v_reply FROM public.messages WHERE id=NEW.reply_to_id; IF v_reply IS DISTINCT FROM NEW.conversation_id THEN NEW.reply_to_id:=NULL; END IF; END IF; RETURN NEW; END $$;
DROP TRIGGER IF EXISTS message_before_insert ON public.messages; DROP TRIGGER IF EXISTS messages_before_insert_trg ON public.messages; CREATE TRIGGER messages_before_insert_trg BEFORE INSERT ON public.messages FOR EACH ROW EXECUTE FUNCTION public.messages_before_insert();
CREATE OR REPLACE FUNCTION public.message_reactions_before_insert() RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$ BEGIN SELECT conversation_id,tenant_id INTO NEW.conversation_id,NEW.tenant_id FROM public.messages WHERE id=NEW.message_id; IF NEW.conversation_id IS NULL THEN RAISE EXCEPTION 'chat: message missing'; END IF; RETURN NEW; END $$;
DROP TRIGGER IF EXISTS reaction_before_insert ON public.message_reactions; DROP TRIGGER IF EXISTS message_reactions_before_insert_trg ON public.message_reactions; CREATE TRIGGER message_reactions_before_insert_trg BEFORE INSERT ON public.message_reactions FOR EACH ROW EXECUTE FUNCTION public.message_reactions_before_insert();
CREATE OR REPLACE FUNCTION public.messages_after_insert() RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$ BEGIN UPDATE public.conversations SET last_message_at=NEW.created_at,last_message_kind=NEW.kind,last_message_preview=CASE WHEN NEW.kind='text' THEN left(NEW.body,140) ELSE NEW.attachment_name END,last_message_sender=NEW.sender_id,updated_at=now() WHERE id=NEW.conversation_id; UPDATE public.conversation_participants SET unread_count=CASE WHEN user_id=NEW.sender_id THEN 0 ELSE unread_count+1 END,last_read_at=CASE WHEN user_id=NEW.sender_id THEN NEW.created_at ELSE last_read_at END,updated_at=now() WHERE conversation_id=NEW.conversation_id; RETURN NEW; END $$;
DROP TRIGGER IF EXISTS message_after_insert ON public.messages; DROP TRIGGER IF EXISTS messages_after_insert_trg ON public.messages; CREATE TRIGGER messages_after_insert_trg AFTER INSERT ON public.messages FOR EACH ROW EXECUTE FUNCTION public.messages_after_insert();
CREATE OR REPLACE FUNCTION public.messages_enforce_edit_window() RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$ BEGIN IF NEW.deleted_at IS NOT NULL THEN NEW.body:=NULL;NEW.attachment_path:=NULL;NEW.attachment_name:=NULL;NEW.attachment_mime:=NULL;NEW.attachment_size:=NULL;RETURN NEW; END IF; IF NEW.attachment_path IS DISTINCT FROM OLD.attachment_path OR NEW.attachment_name IS DISTINCT FROM OLD.attachment_name OR NEW.attachment_mime IS DISTINCT FROM OLD.attachment_mime OR NEW.attachment_size IS DISTINCT FROM OLD.attachment_size THEN RAISE EXCEPTION 'chat: attachments immutable'; END IF; IF NEW.body IS DISTINCT FROM OLD.body THEN IF OLD.deleted_at IS NOT NULL OR OLD.kind<>'text' OR OLD.created_at<now()-interval '5 minutes' THEN RAISE EXCEPTION 'chat: edit denied'; END IF; NEW.edited_at:=now(); END IF; RETURN NEW; END $$;
DROP TRIGGER IF EXISTS message_before_update ON public.messages; DROP TRIGGER IF EXISTS messages_enforce_edit_window_trg ON public.messages; CREATE TRIGGER messages_enforce_edit_window_trg BEFORE UPDATE ON public.messages FOR EACH ROW EXECUTE FUNCTION public.messages_enforce_edit_window();
DROP TRIGGER IF EXISTS conversations_set_updated_at ON public.conversations; CREATE TRIGGER conversations_set_updated_at BEFORE UPDATE ON public.conversations FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();
REVOKE EXECUTE ON FUNCTION public.get_chat_peers(uuid[]) FROM PUBLIC,anon; GRANT EXECUTE ON FUNCTION public.get_chat_peers(uuid[]) TO authenticated,service_role;
REVOKE EXECUTE ON FUNCTION public.search_people(text,integer) FROM PUBLIC,anon; GRANT EXECUTE ON FUNCTION public.search_people(text,integer) TO authenticated,service_role;
REVOKE EXECUTE ON FUNCTION public.get_or_create_direct_conversation(uuid) FROM PUBLIC,anon; GRANT EXECUTE ON FUNCTION public.get_or_create_direct_conversation(uuid) TO authenticated,service_role;
REVOKE EXECUTE ON FUNCTION public.mark_conversation_read(uuid) FROM PUBLIC,anon; GRANT EXECUTE ON FUNCTION public.mark_conversation_read(uuid) TO authenticated,service_role;
DO $$ BEGIN BEGIN ALTER PUBLICATION supabase_realtime ADD TABLE public.messages; EXCEPTION WHEN duplicate_object THEN NULL; END; BEGIN ALTER PUBLICATION supabase_realtime ADD TABLE public.conversation_participants; EXCEPTION WHEN duplicate_object THEN NULL; END; BEGIN ALTER PUBLICATION supabase_realtime ADD TABLE public.message_reactions; EXCEPTION WHEN duplicate_object THEN NULL; END; END $$;